SELECT BPA_ID ,FILE_ID ,FILE_NM ,BATCH_JOB_ID ,SORT_NO ,USE_YN ,ETC1 ,ETC2 ,ETC3 ,RMK FROM MSP_BPA_FILE_INFO WHERE BPA_ID = #{bpaId}
