UPDATE MSP_BPA_FILE_INFO
SET
     FILE_NM = #{fileNm}
    ,BATCH_JOB_ID = #{batchJobId}
    ,SORT_NO = #{sortNo}
    ,USE_YN = #{useYn}
    ,ETC1 = #{etc1}
    ,ETC2 = #{etc2}
    ,ETC3 = #{etc3}
    ,RMK = #{rmk}
    ,RVISN_ID = #{sessionUserId}
    ,RVISN_DTTM = SYSDATE
WHERE BPA_ID = #{bpaId}
AND FILE_ID = #{fileId}

mapper.insert:
INSERT INTO MSP_BPA_UPLOAD_INFO
(
  BPA_ID
,SEQ
,UPLOAD_FILE_NM
,CONTRACT_NUM
,SVC_CNTR_NO
,USE_YN
,REGST_ID
,REGST_DTTM
)
SELECT
    #{bpaId}
     ,#{seq}
     ,#{uploadFileNm}
     ,(SELECT CONTRACT_NUM FROM MSP_JUO_SUB_INFO WHERE SVC_CNTR_NO = #{svcCntrNo})
     ,#{svcCntrNo}
     ,'Y'
     ,#{regstId}
     ,SYSDATE
FROM DUAL
WHERE NOT EXISTS ( SELECT 1 FROM MSP_BPA_UPLOAD_INFO
                   WHERE BPA_ID  = #{bpaId}
                     AND SVC_CNTR_NO = #{svcCntrNo}
)

